# Nginx Configuration: Hardened for OWASP Top 10 Mitigation
# Version: Nginx 1.24+
# Focus: SQLi, XSS, Info Disclosure, Rate Limiting, Secure Headers

# 1. Rate Limiting Zone Definition
# Mitigates: DoS, Brute Force, Credential Stuffing
# Addresses log_snippet anomaly: 5000 requests in 10s from single IP
limit_req_zone $binary_remote_addr zone=api_limit:10m rate=10r/s;
limit_req_zone $binary_remote_addr zone=login_limit:10m rate=5r/s;
limit_req_zone $binary_remote_addr zone=general_limit:10m rate=30r/s;

# 2. Security Headers (Mitigates: XSS, Clickjacking, Info Disclosure)
# Note: These must be set in the server or location block
add_header X-Frame-Options "SAMEORIGIN" always;
add_header X-Content-Type-Options "nosniff" always;
add_header X-XSS-Protection "1; mode=block" always;
add_header Referrer-Policy "strict-origin-when-cross-origin" always;
add_header Content-Security-Policy "default-src 'self'; script-src 'self'; style-src 'self' 'unsafe-inline'; img-src 'self' data:; font-src 'self'; connect-src 'self'; frame-ancestors 'self';" always;
add_header Strict-Transport-Security "max-age=31536000; includeSubDomains; preload" always;
add_header Permissions-Policy "geolocation=(), microphone=(), camera=()" always;

server {
    listen 80;
    listen 443 ssl http2;
    server_name example.com;

    # SSL Configuration (Best Practice)
    ssl_certificate /etc/nginx/ssl/cert.pem;
    ssl_certificate_key /etc/nginx/ssl/key.pem;
    ssl_protocols TLSv1.2 TLSv1.3;
    ssl_ciphers ECDHE-ECDSA-AES128-GCM-SHA256:ECDHE-RSA-AES128-GCM-SHA256:ECDHE-ECDSA-AES256-GCM-SHA384:ECDHE-RSA-AES256-GCM-SHA384;
    ssl_prefer_server_ciphers on;
    ssl_session_cache shared:SSL:10m;
    ssl_session_timeout 1d;

    # Hide Nginx Version (Mitigates: Information Disclosure)
    server_tokens off;

    # Root and Index
    root /var/www/html;
    index index.html index.htm;

    # 3. General Security & Logging
    # Ensure logs do not expose sensitive query parameters
    log_format secure_log '$remote_addr - $remote_user [$time_local] "$request" '
                          '$status $body_bytes_sent "$http_referer" '
                          '"$http_user_agent" rt=$request_time';
    access_log /var/log/nginx/access.log secure_log;
    error_log /var/log/nginx/error.log warn;

    # 4. API & Login Protection (Mitigates: Brute Force, DoS)
    location /api/login {
        # Strict rate limiting for login endpoints
        limit_req zone=login_limit burst=5 nodelay;

        # Deny access if rate limit exceeded
        limit_req_status 429;

        # Proxy to backend (assuming backend handles SQLi/XSS logic)
        # Nginx cannot prevent SQLi in backend code, but can block malicious patterns
        if ($request_uri ~* "(union|select|insert|delete|drop|update|exec|script|alert|onerror)") {
            return 403;
        }

        proxy_pass http://backend_app;
        proxy_set_header Host $host;
        proxy_set_header X-Real-IP $remote_addr;
        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
        proxy_set_header X-Forwarded-Proto $scheme;
    }

    # 5. General API Protection
    location /api/ {
        limit_req zone=api_limit burst=20 nodelay;
        limit_req_status 429;

        # Block common SQL injection and XSS payloads in URI
        if ($request_uri ~* "(union|select|insert|delete|drop|exec|script|<|>|javascript:|onerror|onload)") {
            return 403;
        }

        proxy_pass http://backend_app;
        proxy_set_header Host $host;
        proxy_set_header X-Real-IP $remote_addr;
    }

    # 6. Static Content & Info Disclosure Prevention
    location / {
        limit_req zone=general_limit burst=50 nodelay;

        # Prevent directory listing (Mitigates: Info Disclosure)
        autoindex off;

        # Deny access to hidden files (e.g., .git, .env)
        location ~ /\. {
            deny all;
            return 404;
        }

        # Deny access to backup files
        location ~* \.(bak|config|sql|log|ini|env)$ {
            deny all;
            return 404;
        }

        try_files $uri $uri/ =404;
    }

    # 7. Error Pages (Mitigates: Info Disclosure)
    error_page 400 401 403 404 /404.html;
    error_page 500 502 503 504 /50x.html;
    location = /404.html {
        internal;
        root /var/www/html/errors;
    }
    location = /50x.html {
        internal;
        root /var/www/html/errors;
    }
}
```
